def computation():
    import math
    n = 101
    p = 0.001
    ans = 0.0
    for d in range(1,(n+1)//2):
        chordLen = 2*math.sin(math.pi*d/n)
        numBlockers = ((n+1)/2-d)*((n+3)/2-d)/2-1;
        if d==1:
            ans += n*math.pow(1-p,numBlockers)*chordLen
            continue
        else:
            crossPoints = []
            for a in range(1,d):
                for b in range(1,n-d):
                    dist = 2*math.sin(math.pi*float(a)/float(n))\
                    *math.sin(math.pi*float(b)/float(n))\
                    /math.sin(math.pi*float(a-b+n-d)/float(n))
                    if a+b<=int((n-1)/2):
                        crossPoints.append([dist,"L"])
                    else:
                        crossPoints.append([dist,"R"])
            crossPoints.sort()
            numRsLeft = 0
            numLsRight = len(crossPoints)/2-1
            ans += n*p*math.pow(1-p,numBlockers+len(crossPoints)/2)\
            *crossPoints[0][0] # edge case AP_1
            ans += n*p*math.pow(1-p,numBlockers+len(crossPoints)/2)\
            *(chordLen-crossPoints[len(crossPoints)-1][0]) # edge case P_kB
            for i in range(len(crossPoints)-1):
                ans += n*p*math.pow(1-p,numBlockers+numRsLeft+numLsRight)\
                *(crossPoints[i+1][0]-crossPoints[i][0])
                if crossPoints[i+1][1]=="R":
                    numRsLeft+=1
                if crossPoints[i+1][1]=="L":
                    numLsRight-=1
    return ans

